history.failed_code:
`timescale 1ns/1ps

import rv32ec_zmmul_core_pkg::*;

module rv32ec_zmmul_cpu_top (
  input  logic        clk,
  input  logic        rst_n,
  input  logic        boot_mode_spi,
  input  logic        ext_irq,
  input  logic        instr_ready,
  input  logic [31:0] instr_rdata,
  input  logic        data_ready,
  input  logic [31:0] data_rdata,
  input  logic        spi_ready,
  input  logic [31:0] spi_rdata,
  output logic        instr_req,
  output logic [31:0] instr_addr,
  output logic        data_req,
  output logic        data_we,
  output logic [3:0]  data_be,
  output logic [31:0] data_addr,
  output logic [31:0] data_wdata,
  output logic        spi_req,
  output logic [31:0] spi_addr,
  output logic        fail_stop
);

  typedef enum logic [1:0] {
    TOP_MODE_BOOT = 2'b00,
    TOP_MODE_RUN  = 2'b01,
    TOP_MODE_FAIL = 2'b10
  } top_mode_t;

  top_mode_t mode_q, mode_d;

  logic boot_mode_latched_q;
  logic boot_started_q;
  logic boot_started_d;

  logic [31:0] boot_entry_pc_q;
  logic [31:0] boot_entry_pc_d;

  logic        redirect_override_q;
  logic        redirect_override_d;
  logic [31:0] redirect_override_pc_q;
  logic [31:0] redirect_override_pc_d;

  logic        issue_valid_q;
  logic        issue_valid_d;
  logic [31:0] issue_instr_q;
  logic [31:0] issue_instr_d;
  logic [31:0] issue_pc_q;
  logic [31:0] issue_pc_d;
  logic [31:0] issue_rs1_data_q;
  logic [31:0] issue_rs1_data_d;
  logic [31:0] issue_rs2_data_q;
  logic [31:0] issue_rs2_data_d;
  logic [31:0] issue_imm_q;
  logic [31:0] issue_imm_d;
  logic [4:0]  issue_rd_idx_q;
  logic [4:0]  issue_rd_idx_d;
  logic [3:0]  issue_alu_op_q;
  logic [3:0]  issue_alu_op_d;
  logic [2:0]  issue_branch_op_q;
  logic [2:0]  issue_branch_op_d;
  logic        issue_mul_en_q;
  logic        issue_mul_en_d;
  logic        issue_mem_req_q;
  logic        issue_mem_req_d;
  logic        issue_mem_we_q;
  logic        issue_mem_we_d;
  logic        issue_csr_en_q;
  logic        issue_csr_en_d;
  logic        issue_mret_q;
  logic        issue_mret_d;
  logic        issue_illegal_q;
  logic        issue_illegal_d;

  logic [31:0] fetch_pc;
  logic [31:0] fetch_instr;
  logic        fetch_instr_valid;
  logic        fetch_instr_req;
  logic [31:0] fetch_instr_addr;
  logic        fetch_stall;
  logic        fetch_flush;
  logic        fetch_is_compressed_hint;
  logic        fetch_branch_redirect_valid;
  logic [31:0] fetch_branch_redirect_pc;

  logic [4:0]  dec_rs1_idx;
  logic [4:0]  dec_rs2_idx;
  logic [4:0]  dec_rd_idx;
  logic [31:0] dec_imm;
  logic [3:0]  dec_alu_op;
  logic [2:0]  dec_branch_op;
  logic        dec_mul_en;
  logic        dec_mem_req;
  logic        dec_mem_we;
  logic        dec_csr_en;
  logic        dec_mret;
  logic        dec_ebreak;
  logic        dec_illegal;
  logic        dec_is_compressed;
  logic        dec_wb_en;

  logic [31:0] rf_rs1_data;
  logic [31:0] rf_rs2_data;
  logic [3:0]  rf_raddr1;
  logic [3:0]  rf_raddr2;
  logic        rf_we;
  logic [3:0]  rf_waddr;
  logic [31:0] rf_wdata;

  logic [31:0] shadow_alu_result;
  logic        shadow_branch_taken;
  logic [31:0] shadow_branch_target;

  logic        mul_start;
  logic        mul_busy;
  logic        mul_done;
  logic [31:0] mul_result;

  logic        ex_branch_taken;
  logic [31:0] ex_branch_target;
  logic        ex_wb_en;
  logic [4:0]  ex_wb_rd_idx;
  logic [31:0] ex_wb_data;
  logic [31:0] ex_mem_addr;
  logic [31:0] ex_mem_wdata;
  logic        ex_mem_req;
  logic        ex_mem_we;
  logic        ex_trap_req;
  logic [3:0]  ex_trap_cause;
  logic        ex_mret_req;
  logic        ex_stall;

  logic        lsu_req_i;
  logic        lsu_we_i;
  logic [1:0]  lsu_size_i;
  logic        lsu_unsigned_i;
  logic        lsu_mem_req;
  logic        lsu_mem_we;
  logic [3:0]  lsu_mem_be;
  logic [31:0] lsu_mem_addr;
  logic [31:0] lsu_mem_wdata;
  logic [31:0] lsu_load_data;
  logic        lsu_done;
  logic        lsu_stall;
  logic        lsu_misaligned;

  logic [11:0] csr_addr;
  logic        csr_we;
  logic [31:0] csr_wdata;
  logic [31:0] csr_rdata;
  logic        csr_trap_redirect_valid;
  logic [31:0] csr_trap_redirect_pc;
  logic        csr_mret_redirect_valid;
  logic [31:0] csr_mret_redirect_pc;

  logic        boot_start;
  logic        boot_spi_req;
  logic [31:0] boot_spi_addr;
  logic        boot_iram_we;
  logic [31:0] boot_iram_addr;
  logic [31:0] boot_iram_wdata;
  logic        boot_done;
  logic [31:0] boot_pc;
  logic        boot_fail_stop;

  logic        run_active;
  logic        core_busy;
  logic        issue_accept;
  logic        redirect_event;
  logic [31:0] redirect_event_pc;
  logic        pending_flush;

  assign run_active = (mode_q == TOP_MODE_RUN);
  assign core_busy  = ex_stall | lsu_stall;
  assign issue_accept = run_active & fetch_instr_valid & ~core_busy & ~redirect_override_q;

  assign rf_raddr1 = dec_rs1_idx[RV32EC_ZMMUL_REG_ADDR_W-1:0];
  assign rf_raddr2 = dec_rs2_idx[RV32EC_ZMMUL_REG_ADDR_W-1:0];

  assign mul_start = issue_valid_q & issue_mul_en_q;

  assign csr_addr  = issue_instr_q[31:20];
  assign csr_wdata = issue_rs1_data_q;
  assign csr_we    = issue_valid_q & issue_csr_en_q & (issue_instr_q[14:12] != 3'b010);

  always_comb begin
    lsu_req_i      = ex_mem_req;
    lsu_we_i       = ex_mem_we;
    lsu_size_i     = 2'b10;
    lsu_unsigned_i = 1'b0;

    unique case (issue_instr_q[14:12])
      3'b000: begin
        lsu_size_i     = 2'b00;
        lsu_unsigned_i = 1'b0;
      end
      3'b001: begin
        lsu_size_i     = 2'b01;
        lsu_unsigned_i = 1'b0;
      end
      3'b010: begin
        lsu_size_i     = 2'b10;
        lsu_unsigned_i = 1'b0;
      end
      3'b100: begin
        lsu_size_i     = 2'b00;
        lsu_unsigned_i = 1'b1;
      end
      3'b101: begin
        lsu_size_i     = 2'b01;
        lsu_unsigned_i = 1'b1;
      end
      default: begin
        lsu_size_i     = 2'b10;
        lsu_unsigned_i = 1'b0;
      end
    endcase
  end

  always_comb begin
    redirect_event    = 1'b0;
    redirect_event_pc = 32'h0000_0000;

    if (boot_done && (mode_q == TOP_MODE_BOOT)) begin
      redirect_event    = 1'b1;
      redirect_event_pc = boot_pc;
    end else if (csr_trap_redirect_valid) begin
      redirect_event    = 1'b1;
      redirect_event_pc = csr_trap_redirect_pc;
    end else if (csr_mret_redirect_valid) begin
      redirect_event    = 1'b1;
      redirect_event_pc = csr_mret_redirect_pc;
    end else if (ex_branch_taken) begin
      redirect_event    = 1'b1;
      redirect_event_pc = ex_branch_target;
    end
  end

  always_comb begin
    fetch_branch_redirect_valid = redirect_override_q | redirect_event;
    fetch_branch_redirect_pc    = redirect_override_q ? redirect_override_pc_q : redirect_event_pc;
    pending_flush               = issue_accept | redirect_event | redirect_override_q;
    fetch_flush                 = run_active & pending_flush;
    fetch_stall                 = (~run_active) | core_busy;
    fetch_is_compressed_hint    = dec_is_compressed;
  end

  always_comb begin
    mode_d                 = mode_q;
    boot_started_d         = boot_started_q;
    boot_entry_pc_d        = boot_entry_pc_q;
    redirect_override_d    = 1'b0;
    redirect_override_pc_d = redirect_override_pc_q;

    issue_valid_d          = 1'b0;
    issue_instr_d          = issue_instr_q;
    issue_pc_d             = issue_pc_q;
    issue_rs1_data_d       = issue_rs1_data_q;
    issue_rs2_data_d       = issue_rs2_data_q;
    issue_imm_d            = issue_imm_q;
    issue_rd_idx_d         = issue_rd_idx_q;
    issue_alu_op_d         = issue_alu_op_q;
    issue_branch_op_d      = issue_branch_op_q;
    issue_mul_en_d         = issue_mul_en_q;
    issue_mem_req_d        = issue_mem_req_q;
    issue_mem_we_d         = issue_mem_we_q;
    issue_csr_en_d         = issue_csr_en_q;
    issue_mret_d           = issue_mret_q;
    issue_illegal_d        = issue_illegal_q;

    if (mode_q == TOP_MODE_BOOT) begin
      if (!boot_started_q) begin
        boot_started_d = 1'b1;
      end
      if (boot_fail_stop) begin
        mode_d = TOP_MODE_FAIL;
      end else if (boot_done) begin
        mode_d                 = TOP_MODE_RUN;
        boot_entry_pc_d        = boot_pc;
        redirect_override_d    = 1'b1;
        redirect_override_pc_d = boot_pc;
      end
    end else if (mode_q == TOP_MODE_RUN) begin
      if (issue_accept) begin
        issue_valid_d     = 1'b1;
        issue_instr_d     = fetch_instr;
        issue_pc_d        = fetch_pc;
        issue_rs1_data_d  = rf_rs1_data;
        issue_rs2_data_d  = rf_rs2_data;
        issue_imm_d       = dec_imm;
        issue_rd_idx_d    = dec_rd_idx;
        issue_alu_op_d    = dec_alu_op;
        issue_branch_op_d = dec_branch_op;
        issue_mul_en_d    = dec_mul_en;
        issue_mem_req_d   = dec_mem_req;
        issue_mem_we_d    = dec_mem_we;
        issue_csr_en_d    = dec_csr_en;
        issue_mret_d      = dec_mret;
        issue_illegal_d   = dec_illegal | dec_ebreak;
      end

      if (csr_trap_redirect_valid) begin
        redirect_override_d    = 1'b1;
        redirect_override_pc_d = csr_trap_redirect_pc;
      end else if (csr_mret_redirect_valid) begin
        redirect_override_d    = 1'b1;
        redirect_override_pc_d = csr_mret_redirect_pc;
      end else if (ex_branch_taken) begin
        redirect_override_d    = 1'b1;
        redirect_override_pc_d = ex_branch_target;
      end
    end else begin
      mode_d = TOP_MODE_FAIL;
    end
  end

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      mode_q                 <= boot_mode_spi ? TOP_MODE_BOOT : TOP_MODE_RUN;
      boot_mode_latched_q    <= boot_mode_spi;
      boot_started_q         <= 1'b0;
      boot_entry_pc_q        <= RV32EC_ZMMUL_RESET_VECTOR;
      redirect_override_q    <= 1'b0;
      redirect_override_pc_q <= RV32EC_ZMMUL_RESET_VECTOR;

      issue_valid_q          <= 1'b0;
      issue_instr_q          <= 32'h0000_0013;
      issue_pc_q             <= RV32EC_ZMMUL_RESET_VECTOR;
      issue_rs1_data_q       <= 32'h0000_0000;
      issue_rs2_data_q       <= 32'h0000_0000;
      issue_imm_q            <= 32'h0000_0000;
      issue_rd_idx_q         <= 5'd0;
      issue_alu_op_q         <= 4'd0;
      issue_branch_op_q      <= 3'd0;
      issue_mul_en_q         <= 1'b0;
      issue_mem_req_q        <= 1'b0;
      issue_mem_we_q         <= 1'b0;
      issue_csr_en_q         <= 1'b0;
      issue_mret_q           <= 1'b0;
      issue_illegal_q        <= 1'b0;
    end else begin
      mode_q                 <= mode_d;
      boot_mode_latched_q    <= boot_mode_latched_q;
      boot_started_q         <= boot_started_d;
      boot_entry_pc_q        <= boot_entry_pc_d;
      redirect_override_q    <= redirect_override_d;
      redirect_override_pc_q <= redirect_override_pc_d;

      issue_valid_q          <= issue_valid_d;
      issue_instr_q          <= issue_instr_d;
      issue_pc_q             <= issue_pc_d;
      issue_rs1_data_q       <= issue_rs1_data_d;
      issue_rs2_data_q       <= issue_rs2_data_d;
      issue_imm_q            <= issue_imm_d;
      issue_rd_idx_q         <= issue_rd_idx_d;
      issue_alu_op_q         <= issue_alu_op_d;
      issue_branch_op_q      <= issue_branch_op_d;
      issue_mul_en_q         <= issue_mul_en_d;
      issue_mem_req_q        <= issue_mem_req_d;
      issue_mem_we_q         <= issue_mem_we_d;
      issue_csr_en_q         <= issue_csr_en_d;
      issue_mret_q           <= issue_mret_d;
      issue_illegal_q        <= issue_illegal_d;
    end
  end

  assign boot_start = (mode_q == TOP_MODE_BOOT) & ~boot_started_q;

  fetch_unit u_fetch_unit (
    .reset_vector_i          (RV32EC_ZMMUL_RESET_VECTOR),
    .clk                     (clk),
    .rst_n                   (rst_n),
    .stall_i                 (fetch_stall),
    .flush_i                 (fetch_flush),
    .trap_redirect_valid_i   (csr_trap_redirect_valid),
    .trap_redirect_pc_i      (csr_trap_redirect_pc),
    .mret_redirect_valid_i   (csr_mret_redirect_valid),
    .mret_redirect_pc_i      (csr_mret_redirect_pc),
    .branch_redirect_valid_i (fetch_branch_redirect_valid),
    .branch_redirect_pc_i    (fetch_branch_redirect_pc),
    .instr_ready_i           (instr_ready),
    .instr_rdata_i           (instr_rdata),
    .is_compressed_i         (fetch_is_compressed_hint),
    .instr_req_o             (fetch_instr_req),
    .instr_addr_o            (fetch_instr_addr),
    .pc_o                    (fetch_pc),
    .instr_valid_o           (fetch_instr_valid),
    .instr_o                 (fetch_instr)
  );

  decode_control_unit u_decode_control_unit (
    .instr_i         (fetch_instr),
    .pc_i            (fetch_pc),
    .rs1_idx_o       (dec_rs1_idx),
    .rs2_idx_o       (dec_rs2_idx),
    .rd_idx_o        (dec_rd_idx),
    .imm_o           (dec_imm),
    .alu_op_o        (dec_alu_op),
    .branch_op_o     (dec_branch_op),
    .mul_en_o        (dec_mul_en),
    .mem_req_o       (dec_mem_req),
    .mem_we_o        (dec_mem_we),
    .csr_en_o        (dec_csr_en),
    .mret_o          (dec_mret),
    .ebreak_o        (dec_ebreak),
    .illegal_o       (dec_illegal),
    .is_compressed_o (dec_is_compressed),
    .wb_en_o         (dec_wb_en)
  );

  regfile_16x32 u_regfile_16x32 (
    .clk      (clk),
    .rst_n    (rst_n),
    .raddr1_i (rf_raddr1),
    .raddr2_i (rf_raddr2),
    .we_i     (rf_we),
    .waddr_i  (rf_waddr),
    .wdata_i  (rf_wdata),
    .rdata1_o (rf_rs1_data),
    .rdata2_o (rf_rs2_data)
  );

  alu32_branch_unit u_alu32_branch_unit (
    .op_a_i          (rf_rs1_data),
    .op_b_i          (rf_rs2_data),
    .pc_i            (fetch_pc),
    .imm_i           (dec_imm),
    .alu_op_i        (dec_alu_op),
    .branch_op_i     (dec_branch_op),
    .result_o        (shadow_alu_result),
    .branch_taken_o  (shadow_branch_taken),
    .branch_target_o (shadow_branch_target)
  );

  multiplier_unit u_multiplier_unit (
    .clk      (clk),
    .rst_n    (rst_n),
    .start_i  (mul_start),
    .op_a_i   (issue_rs1_data_q),
    .op_b_i   (issue_rs2_data_q),
    .busy_o   (mul_busy),
    .done_o   (mul_done),
    .result_o (mul_result)
  );

  execute_writeback_unit u_execute_writeback_unit (
    .clk            (clk),
    .rst_n          (rst_n),
    .pc_i           (issue_pc_q),
    .rs1_data_i     (issue_valid_q ? issue_rs1_data_q : 32'h0000_0000),
    .rs2_data_i     (issue_valid_q ? issue_rs2_data_q : 32'h0000_0000),
    .imm_i          (issue_valid_q ? issue_imm_q : 32'h0000_0000),
    .rd_idx_i       (issue_valid_q ? issue_rd_idx_q : 5'd0),
    .alu_op_i       (issue_valid_q ? issue_alu_op_q : 4'd0),
    .branch_op_i    (issue_valid_q ? issue_branch_op_q : 3'd0),
    .mul_en_i       (issue_valid_q & issue_mul_en_q),
    .mem_req_i      (issue_valid_q & issue_mem_req_q),
    .mem_we_i       (issue_valid_q & issue_mem_we_q),
    .csr_en_i       (issue_valid_q & issue_csr_en_q),
    .mret_i         (issue_valid_q & issue_mret_q),
    .illegal_i      (issue_valid_q & issue_illegal_q),
    .load_data_i    (lsu_load_data),
    .load_ready_i   (lsu_done),
    .mul_result_i   (mul_result),
    .mul_done_i     (mul_done),
    .csr_rdata_i    (csr_rdata),
    .branch_taken_o (ex_branch_taken),
    .branch_target_o(ex_branch_target),
    .wb_en_o        (ex_wb_en),
    .wb_rd_idx_o    (ex_wb_rd_idx),
    .wb_data_o      (ex_wb_data),
    .mem_addr_o     (ex_mem_addr),
    .mem_wdata_o    (ex_mem_wdata),
    .mem_req_o      (ex_mem_req),
    .mem_we_o       (ex_mem_we),
    .trap_req_o     (ex_trap_req),
    .trap_cause_o   (ex_trap_cause),
    .mret_req_o     (ex_mret_req),
    .stall_o        (ex_stall)
  );

  load_store_unit u_load_store_unit (
    .clk                   (clk),
    .rst_n                 (rst_n),
    .req_i                 (lsu_req_i),
    .we_i                  (lsu_we_i),
    .size_i                (lsu_size_i),
    .unsigned_i            (lsu_unsigned_i),
    .base_addr_i           (ex_mem_addr),
    .offset_i              (32'h0000_0000),
    .store_data_i          (ex_mem_wdata),
    .mem_ready_i           (data_ready),
    .mem_rdata_i           (data_rdata),
    .trap_on_misaligned_i  (1'b1),
    .mem_req_o             (lsu_mem_req),
    .mem_we_o              (lsu_mem_we),
    .mem_be_o              (lsu_mem_be),
    .mem_addr_o            (lsu_mem_addr),
    .mem_wdata_o           (lsu_mem_wdata),
    .load_data_o           (lsu_load_data),
    .done_o                (lsu_done),
    .stall_o               (lsu_stall),
    .misaligned_o          (lsu_misaligned)
  );

  csr_trap_controller u_csr_trap_controller (
    .clk                   (clk),
    .rst_n                 (rst_n),
    .csr_en_i              (issue_valid_q & issue_csr_en_q),
    .csr_we_i              (csr_we),
    .csr_addr_i            (csr_addr),
    .csr_wdata_i           (csr_wdata),
    .trap_req_i            (ex_trap_req | lsu_misaligned),
    .trap_cause_i          (lsu_misaligned ? 4'd4 : ex_trap_cause),
    .trap_pc_i             (issue_pc_q),
    .ext_irq_i             (run_active ? ext_irq : 1'b0),
    .mret_i                (ex_mret_req),
    .csr_rdata_o           (csr_rdata),
    .trap_redirect_valid_o (csr_trap_redirect_valid),
    .trap_redirect_pc_o    (csr_trap_redirect_pc),
    .mret_redirect_valid_o (csr_mret_redirect_valid),
    .mret_redirect_pc_o    (csr_mret_redirect_pc)
  );

  boot_rom_loader u_boot_rom_loader (
    .clk                 (clk),
    .rst_n               (rst_n),
    .start_i             (boot_start),
    .spi_ready_i         (spi_ready),
    .spi_rdata_i         (spi_rdata),
    .iram_ready_i        (1'b1),
    .validation_enable_i (1'b0),
    .spi_req_o           (boot_spi_req),
    .spi_addr_o          (boot_spi_addr),
    .iram_we_o           (boot_iram_we),
    .iram_addr_o         (boot_iram_addr),
    .iram_wdata_o        (boot_iram_wdata),
    .done_o              (boot_done),
    .boot_pc_o           (boot_pc),
    .fail_stop_o         (boot_fail_stop)
  );

  always_comb begin
    rf_we    = 1'b0;
    rf_waddr = 4'd0;
    rf_wdata = 32'h0000_0000;

    if (run_active && ex_wb_en && (ex_wb_rd_idx < 5'd16) && (ex_wb_rd_idx != 5'd0)) begin
      rf_we    = 1'b1;
      rf_waddr = ex_wb_rd_idx[RV32EC_ZMMUL_REG_ADDR_W-1:0];
      rf_wdata = ex_wb_data;
    end
  end

  always_comb begin
    fail_stop = (mode_q == TOP_MODE_FAIL);

    instr_req   = 1'b0;
    instr_addr  = 32'h0000_0000;
    data_req    = 1'b0;
    data_we     = 1'b0;
    data_be     = 4'b0000;
    data_addr   = 32'h0000_0000;
    data_wdata  = 32'h0000_0000;
    spi_req     = 1'b0;
    spi_addr    = 32'h0000_0000;

    if (mode_q == TOP_MODE_BOOT) begin
      spi_req  = boot_spi_req & ~boot_fail_stop;
      spi_addr = boot_spi_addr;
    end else if (mode_q == TOP_MODE_RUN) begin
      instr_req  = redirect_override_q ? 1'b1 : fetch_instr_req;
      instr_addr = redirect_override_q ? redirect_override_pc_q : fetch_instr_addr;

      data_req   = lsu_mem_req;
      data_we    = lsu_mem_we;
      data_be    = lsu_mem_be;
      data_addr  = lsu_mem_addr;
      data_wdata = lsu_mem_wdata;
    end
  end

endmodule

`timescale 1ns/1ps

import rv32ec_zmmul_core_pkg::*;

module rv32ec_zmmul_cpu_top (
  input  logic                         clk,
  input  logic                         rst_n,
  input  logic                         boot_mode_spi,
  input  logic                         ext_irq,
  input  logic                         instr_ready,
  input  logic [31:0]                  instr_rdata,
  input  logic                         data_ready,
  input  logic [31:0]                  data_rdata,
  input  logic                         spi_ready,
  input  logic [31:0]                  spi_rdata,
  output logic                         instr_req,
  output logic [31:0]                  instr_addr,
  output logic                         data_req,
  output logic                         data_we,
  output logic [3:0]                   data_be,
  output logic [31:0]                  data_addr,
  output logic [31:0]                  data_wdata,
  output logic                         spi_req,
  output logic [31:0]                  spi_addr,
  output logic                         fail_stop
);

  typedef enum logic [1:0] {
    TOP_MODE_INIT = 2'b00,
    TOP_MODE_BOOT = 2'b01,
    TOP_MODE_RUN  = 2'b10,
    TOP_MODE_FAIL = 2'b11
  } top_mode_e;

  typedef enum logic [1:0] {
    REDIR_NONE   = 2'b00,
    REDIR_BRANCH = 2'b01,
    REDIR_TRAP   = 2'b10,
    REDIR_MRET   = 2'b11
  } redirect_kind_e;

  top_mode_e       mode_q, mode_d;
  redirect_kind_e  redirect_kind_q, redirect_kind_d;

  logic            redirect_override_q, redirect_override_d;
  logic [31:0]     redirect_override_pc_q, redirect_override_pc_d;

  logic            consumed_q, consumed_d;
  logic [31:0]     consumed_pc_q, consumed_pc_d;
  logic [31:0]     consumed_instr_q, consumed_instr_d;

  logic [31:0]     exec_pc_q, exec_pc_d;

  logic            effective_boot_mode;
  logic            effective_run_mode;
  logic            effective_fail_mode;

  logic            fetch_stall;
  logic            fetch_flush;

  logic            fetch_instr_req;
  logic [31:0]     fetch_instr_addr;
  logic [31:0]     fetch_pc;
  logic            fetch_instr_valid;
  logic [31:0]     fetch_instr;

  logic [4:0]      dec_rs1_idx;
  logic [4:0]      dec_rs2_idx;
  logic [4:0]      dec_rd_idx;
  logic [31:0]     dec_imm;
  logic [3:0]      dec_alu_op;
  logic [2:0]      dec_branch_op;
  logic            dec_mul_en;
  logic            dec_mem_req;
  logic            dec_mem_we;
  logic            dec_csr_en;
  logic            dec_mret;
  logic            dec_ebreak;
  logic            dec_illegal;
  logic            dec_is_compressed;
  logic            dec_wb_en_unused;

  logic [31:0]     rs1_data;
  logic [31:0]     rs2_data;

  logic            issue_valid;

  logic [1:0]      lsu_size;
  logic            lsu_unsigned;

  logic            mul_start;
  logic            mul_busy;
  logic            mul_done;
  logic [31:0]     mul_result;

  logic [31:0]     alu_result_unused;
  logic            alu_branch_taken_unused;
  logic [31:0]     alu_branch_target_unused;

  logic            lsu_req;
  logic            lsu_we;
  logic [3:0]      lsu_be;
  logic [31:0]     lsu_addr;
  logic [31:0]     lsu_wdata;
  logic [31:0]     lsu_load_data;
  logic            lsu_done;
  logic            lsu_stall;
  logic            lsu_misaligned;

  logic            ex_branch_taken;
  logic [31:0]     ex_branch_target;
  logic            ex_wb_en;
  logic [4:0]      ex_wb_rd_idx;
  logic [31:0]     ex_wb_data;
  logic [31:0]     ex_mem_addr;
  logic [31:0]     ex_mem_wdata;
  logic            ex_mem_req;
  logic            ex_mem_we;
  logic            ex_trap_req;
  logic [3:0]      ex_trap_cause;
  logic            ex_mret_req;
  logic            ex_stall;

  logic            regfile_we;
  logic [3:0]      regfile_waddr;
  logic [31:0]     regfile_wdata;

  logic            csr_we;
  logic [11:0]     csr_addr;
  logic [31:0]     csr_wdata;
  logic [31:0]     csr_rdata;
  logic            csr_trap_redirect_valid;
  logic [31:0]     csr_trap_redirect_pc;
  logic            csr_mret_redirect_valid;
  logic [31:0]     csr_mret_redirect_pc;

  logic            boot_start;
  logic            boot_spi_req;
  logic [31:0]     boot_spi_addr;
  logic            boot_iram_we_unused;
  logic [31:0]     boot_iram_addr_unused;
  logic [31:0]     boot_iram_wdata_unused;
  logic            boot_done;
  logic [31:0]     boot_pc;
  logic            boot_fail_stop;

  logic            new_redirect_event;
  redirect_kind_e  new_redirect_kind;
  logic [31:0]     new_redirect_pc;
  logic            redirect_seen_by_fetch;

  logic            top_trap_req;
  logic [3:0]      top_trap_cause;

  assign effective_boot_mode = ((mode_q == TOP_MODE_INIT) && boot_mode_spi) || (mode_q == TOP_MODE_BOOT);
  assign effective_run_mode  = ((mode_q == TOP_MODE_INIT) && !boot_mode_spi) || (mode_q == TOP_MODE_RUN);
  assign effective_fail_mode = (mode_q == TOP_MODE_FAIL);

  assign issue_valid = effective_run_mode && fetch_instr_valid && !ex_stall && !consumed_q;

  always_comb begin
    unique case (fetch_instr[14:12])
      3'b000: lsu_size = 2'b00;
      3'b001,
      3'b101: lsu_size = 2'b01;
      default: lsu_size = 2'b10;
    endcase

    lsu_unsigned = fetch_instr[14];
  end

  assign mul_start = issue_valid && dec_mul_en && !mul_busy;

  assign csr_addr  = fetch_instr[31:20];
  assign csr_wdata = rs1_data;
  assign csr_we    = issue_valid && dec_csr_en && (fetch_instr[13:12] != 2'b00);

  assign regfile_we    = effective_run_mode && ex_wb_en && (ex_wb_rd_idx[4] == 1'b0);
  assign regfile_waddr = ex_wb_rd_idx[3:0];
  assign regfile_wdata = ex_wb_data;

  assign boot_start = effective_boot_mode;

  assign fetch_stall = effective_fail_mode || ex_stall || (effective_boot_mode && !boot_done);

  assign top_trap_req = ex_trap_req || (issue_valid && dec_ebreak) || lsu_misaligned;
  assign top_trap_cause = lsu_misaligned ? (ex_mem_we ? 4'd6 : 4'd4) :
                          (issue_valid && dec_ebreak) ? 4'd3 :
                          ex_trap_cause;

  always_comb begin
    new_redirect_event = 1'b0;
    new_redirect_kind  = REDIR_NONE;
    new_redirect_pc    = 32'h0000_0000;

    if (csr_trap_redirect_valid) begin
      new_redirect_event = 1'b1;
      new_redirect_kind  = REDIR_TRAP;
      new_redirect_pc    = csr_trap_redirect_pc;
    end else if (csr_mret_redirect_valid) begin
      new_redirect_event = 1'b1;
      new_redirect_kind  = REDIR_MRET;
      new_redirect_pc    = csr_mret_redirect_pc;
    end else if (ex_branch_taken) begin
      new_redirect_event = 1'b1;
      new_redirect_kind  = REDIR_BRANCH;
      new_redirect_pc    = ex_branch_target;
    end else if (boot_done) begin
      new_redirect_event = 1'b1;
      new_redirect_kind  = REDIR_BRANCH;
      new_redirect_pc    = boot_pc;
    end
  end

  assign redirect_seen_by_fetch = fetch_instr_req && (fetch_instr_addr == redirect_override_pc_q);

  always_comb begin
    mode_d                 = mode_q;
    redirect_override_d    = redirect_override_q;
    redirect_override_pc_d = redirect_override_pc_q;
    redirect_kind_d        = redirect_kind_q;
    consumed_d             = consumed_q;
    consumed_pc_d          = consumed_pc_q;
    consumed_instr_d       = consumed_instr_q;
    exec_pc_d              = exec_pc_q;
    fetch_flush            = 1'b0;

    if (mode_q == TOP_MODE_INIT) begin
      mode_d = boot_mode_spi ? TOP_MODE_BOOT : TOP_MODE_RUN;
    end

    if (!fetch_instr_valid) begin
      consumed_d = 1'b0;
    end else if ((fetch_pc != consumed_pc_q) || (fetch_instr != consumed_instr_q)) begin
      consumed_d = 1'b0;
    end

    if (issue_valid) begin
      consumed_d       = 1'b1;
      consumed_pc_d    = fetch_pc;
      consumed_instr_d = fetch_instr;
      exec_pc_d        = fetch_pc;
    end

    if (new_redirect_event) begin
      redirect_override_d    = 1'b1;
      redirect_override_pc_d = new_redirect_pc;
      redirect_kind_d        = new_redirect_kind;
      fetch_flush            = 1'b1;
      consumed_d             = 1'b0;
    end else if (redirect_override_q && redirect_seen_by_fetch) begin
      redirect_override_d = 1'b0;
      redirect_kind_d     = REDIR_NONE;
    end

    if (boot_fail_stop) begin
      mode_d = TOP_MODE_FAIL;
    end else begin
      unique case (mode_q)
        TOP_MODE_INIT: begin
          mode_d = boot_mode_spi ? TOP_MODE_BOOT : TOP_MODE_RUN;
        end
        TOP_MODE_BOOT: begin
          if (boot_done) begin
            mode_d = TOP_MODE_RUN;
          end
        end
        TOP_MODE_RUN: begin
          mode_d = TOP_MODE_RUN;
        end
        TOP_MODE_FAIL: begin
          mode_d = TOP_MODE_FAIL;
        end
        default: begin
          mode_d = TOP_MODE_FAIL;
        end
      endcase
    end
  end

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      mode_q                 <= TOP_MODE_INIT;
      redirect_override_q    <= 1'b0;
      redirect_override_pc_q <= RV32EC_ZMMUL_RESET_VECTOR;
      redirect_kind_q        <= REDIR_NONE;
      consumed_q             <= 1'b0;
      consumed_pc_q          <= 32'h0000_0000;
      consumed_instr_q       <= 32'h0000_0000;
      exec_pc_q              <= RV32EC_ZMMUL_RESET_VECTOR;
    end else begin
      mode_q                 <= mode_d;
      redirect_override_q    <= redirect_override_d;
      redirect_override_pc_q <= redirect_override_pc_d;
      redirect_kind_q        <= redirect_kind_d;
      consumed_q             <= consumed_d;
      consumed_pc_q          <= consumed_pc_d;
      consumed_instr_q       <= consumed_instr_d;
      exec_pc_q              <= exec_pc_d;
    end
  end

  fetch_unit u_fetch_unit (
    .reset_vector_i         (RV32EC_ZMMUL_RESET_VECTOR),
    .clk                    (clk),
    .rst_n                  (rst_n),
    .stall_i                (fetch_stall),
    .flush_i                (fetch_flush),
    .trap_redirect_valid_i  (csr_trap_redirect_valid || (redirect_override_q && (redirect_kind_q == REDIR_TRAP))),
    .trap_redirect_pc_i     (redirect_override_q && (redirect_kind_q == REDIR_TRAP) ? redirect_override_pc_q : csr_trap_redirect_pc),
    .mret_redirect_valid_i  (csr_mret_redirect_valid || (redirect_override_q && (redirect_kind_q == REDIR_MRET))),
    .mret_redirect_pc_i     (redirect_override_q && (redirect_kind_q == REDIR_MRET) ? redirect_override_pc_q : csr_mret_redirect_pc),
    .branch_redirect_valid_i(ex_branch_taken || boot_done || (redirect_override_q && (redirect_kind_q == REDIR_BRANCH))),
    .branch_redirect_pc_i   (redirect_override_q && (redirect_kind_q == REDIR_BRANCH) ? redirect_override_pc_q :
                             boot_done ? boot_pc : ex_branch_target),
    .instr_ready_i          (instr_ready),
    .instr_rdata_i          (instr_rdata),
    .is_compressed_i        (dec_is_compressed),
    .instr_req_o            (fetch_instr_req),
    .instr_addr_o           (fetch_instr_addr),
    .pc_o                   (fetch_pc),
    .instr_valid_o          (fetch_instr_valid),
    .instr_o                (fetch_instr)
  );

  decode_control_unit u_decode_control_unit (
    .instr_i         (fetch_instr),
    .pc_i            (fetch_pc),
    .rs1_idx_o       (dec_rs1_idx),
    .rs2_idx_o       (dec_rs2_idx),
    .rd_idx_o        (dec_rd_idx),
    .imm_o           (dec_imm),
    .alu_op_o        (dec_alu_op),
    .branch_op_o     (dec_branch_op),
    .mul_en_o        (dec_mul_en),
    .mem_req_o       (dec_mem_req),
    .mem_we_o        (dec_mem_we),
    .csr_en_o        (dec_csr_en),
    .mret_o          (dec_mret),
    .ebreak_o        (dec_ebreak),
    .illegal_o       (dec_illegal),
    .is_compressed_o (dec_is_compressed),
    .wb_en_o         (dec_wb_en_unused)
  );

  regfile_16x32 u_regfile_16x32 (
    .clk     (clk),
    .rst_n   (rst_n),
    .raddr1_i(dec_rs1_idx[3:0]),
    .raddr2_i(dec_rs2_idx[3:0]),
    .we_i    (regfile_we),
    .waddr_i (regfile_waddr),
    .wdata_i (regfile_wdata),
    .rdata1_o(rs1_data),
    .rdata2_o(rs2_data)
  );

  alu32_branch_unit u_alu32_branch_unit (
    .op_a_i         (rs1_data),
    .op_b_i         (rs2_data),
    .pc_i           (fetch_pc),
    .imm_i          (dec_imm),
    .alu_op_i       (dec_alu_op),
    .branch_op_i    (dec_branch_op),
    .result_o       (alu_result_unused),
    .branch_taken_o (alu_branch_taken_unused),
    .branch_target_o(alu_branch_target_unused)
  );

  multiplier_unit u_multiplier_unit (
    .clk     (clk),
    .rst_n   (rst_n),
    .start_i (mul_start),
    .op_a_i  (rs1_data),
    .op_b_i  (rs2_data),
    .busy_o  (mul_busy),
    .done_o  (mul_done),
    .result_o(mul_result)
  );

  load_store_unit u_load_store_unit (
    .clk                  (clk),
    .rst_n                (rst_n),
    .req_i                (issue_valid && dec_mem_req),
    .we_i                 (dec_mem_we),
    .size_i               (lsu_size),
    .unsigned_i           (lsu_unsigned),
    .base_addr_i          (ex_mem_addr),
    .offset_i             (32'h0000_0000),
    .store_data_i         (ex_mem_wdata),
    .mem_ready_i          (data_ready),
    .mem_rdata_i          (data_rdata),
    .trap_on_misaligned_i (1'b1),
    .mem_req_o            (lsu_req),
    .mem_we_o             (lsu_we),
    .mem_be_o             (lsu_be),
    .mem_addr_o           (lsu_addr),
    .mem_wdata_o          (lsu_wdata),
    .load_data_o          (lsu_load_data),
    .done_o               (lsu_done),
    .stall_o              (lsu_stall),
    .misaligned_o         (lsu_misaligned)
  );

  csr_trap_controller u_csr_trap_controller (
    .clk                   (clk),
    .rst_n                 (rst_n),
    .csr_en_i              (issue_valid && dec_csr_en),
    .csr_we_i              (csr_we),
    .csr_addr_i            (csr_addr),
    .csr_wdata_i           (csr_wdata),
    .trap_req_i            (top_trap_req),
    .trap_cause_i          (top_trap_cause),
    .trap_pc_i             (exec_pc_q),
    .ext_irq_i             (effective_run_mode && ext_irq),
    .mret_i                (ex_mret_req),
    .csr_rdata_o           (csr_rdata),
    .trap_redirect_valid_o (csr_trap_redirect_valid),
    .trap_redirect_pc_o    (csr_trap_redirect_pc),
    .mret_redirect_valid_o (csr_mret_redirect_valid),
    .mret_redirect_pc_o    (csr_mret_redirect_pc)
  );

  boot_rom_loader u_boot_rom_loader (
    .clk                 (clk),
    .rst_n               (rst_n),
    .start_i             (boot_start),
    .spi_ready_i         (spi_ready),
    .spi_rdata_i         (spi_rdata),
    .iram_ready_i        (1'b1),
    .validation_enable_i (effective_boot_mode),
    .spi_req_o           (boot_spi_req),
    .spi_addr_o          (boot_spi_addr),
    .iram_we_o           (boot_iram_we_unused),
    .iram_addr_o         (boot_iram_addr_unused),
    .iram_wdata_o        (boot_iram_wdata_unused),
    .done_o              (boot_done),
    .boot_pc_o           (boot_pc),
    .fail_stop_o         (boot_fail_stop)
  );

  execute_writeback_unit u_execute_writeback_unit (
    .clk          (clk),
    .rst_n        (rst_n),
    .pc_i         (fetch_pc),
    .rs1_data_i   (rs1_data),
    .rs2_data_i   (rs2_data),
    .imm_i        (dec_imm),
    .rd_idx_i     (dec_rd_idx),
    .alu_op_i     (dec_alu_op),
    .branch_op_i  (dec_branch_op),
    .mul_en_i     (issue_valid && dec_mul_en),
    .mem_req_i    (issue_valid && dec_mem_req),
    .mem_we_i     (dec_mem_we),
    .csr_en_i     (issue_valid && dec_csr_en),
    .mret_i       (issue_valid && dec_mret),
    .illegal_i    (issue_valid && dec_illegal),
    .load_data_i  (lsu_load_data),
    .load_ready_i (lsu_done),
    .mul_result_i (mul_result),
    .mul_done_i   (mul_done),
    .csr_rdata_i  (csr_rdata),
    .branch_taken_o(ex_branch_taken),
    .branch_target_o(ex_branch_target),
    .wb_en_o      (ex_wb_en),
    .wb_rd_idx_o  (ex_wb_rd_idx),
    .wb_data_o    (ex_wb_data),
    .mem_addr_o   (ex_mem_addr),
    .mem_wdata_o  (ex_mem_wdata),
    .mem_req_o    (ex_mem_req),
    .mem_we_o     (ex_mem_we),
    .trap_req_o   (ex_trap_req),
    .trap_cause_o (ex_trap_cause),
    .mret_req_o   (ex_mret_req),
    .stall_o      (ex_stall)
  );

  always_comb begin
    instr_req   = 1'b0;
    instr_addr  = 32'h0000_0000;
    data_req    = 1'b0;
    data_we     = 1'b0;
    data_be     = 4'b0000;
    data_addr   = 32'h0000_0000;
    data_wdata  = 32'h0000_0000;
    spi_req     = 1'b0;
    spi_addr    = 32'h0000_0000;
    fail_stop   = effective_fail_mode || boot_fail_stop;

    if (effective_boot_mode && !fail_stop) begin
      spi_req  = boot_spi_req;
      spi_addr = boot_spi_addr;
    end else if (effective_run_mode && !fail_stop) begin
      instr_req  = redirect_override_q ? 1'b1 : fetch_instr_req;
      instr_addr = redirect_override_q ? redirect_override_pc_q : fetch_instr_addr;

      data_req   = lsu_req;
      data_we    = lsu_we;
      data_be    = lsu_be;
      data_addr  = lsu_addr;
      data_wdata = lsu_wdata;
    end
  end

endmodule

`timescale 1ns/1ps

import rv32ec_zmmul_core_pkg::*;

module rv32ec_zmmul_cpu_top (
  input  logic                         clk,
  input  logic                         rst_n,
  input  logic                         boot_mode_spi,
  input  logic                         ext_irq,
  input  logic                         instr_ready,
  input  logic [31:0]                  instr_rdata,
  input  logic                         data_ready,
  input  logic [31:0]                  data_rdata,
  input  logic                         spi_ready,
  input  logic [31:0]                  spi_rdata,
  output logic                         instr_req,
  output logic [31:0]                  instr_addr,
  output logic                         data_req,
  output logic                         data_we,
  output logic [3:0]                   data_be,
  output logic [31:0]                  data_addr,
  output logic [31:0]                  data_wdata,
  output logic                         spi_req,
  output logic [31:0]                  spi_addr,
  output logic                         fail_stop
);

  localparam logic [1:0] TOP_STATE_INIT = 2'd0;
  localparam logic [1:0] TOP_STATE_BOOT = 2'd1;
  localparam logic [1:0] TOP_STATE_RUN  = 2'd2;
  localparam logic [1:0] TOP_STATE_FAIL = 2'd3;

  logic [1:0] top_state_q;
  logic       fail_stop_q;
  logic       boot_started_q;
  logic       boot_redirect_pending_q;
  logic [31:0] boot_redirect_pc_q;

  logic        fetch_stall_w;
  logic        fetch_flush_w;
  logic        fetch_instr_req_w;
  logic [31:0] fetch_instr_addr_w;
  logic [31:0] fetch_pc_w;
  logic        fetch_instr_valid_w;
  logic [31:0] fetch_instr_w;
  logic        fetch_is_compressed_hint_w;

  logic [4:0]  dec_rs1_idx_w;
  logic [4:0]  dec_rs2_idx_w;
  logic [4:0]  dec_rd_idx_w;
  logic [31:0] dec_imm_w;
  logic [3:0]  dec_alu_op_w;
  logic [2:0]  dec_branch_op_w;
  logic        dec_mul_en_w;
  logic        dec_mem_req_w;
  logic        dec_mem_we_w;
  logic        dec_csr_en_w;
  logic        dec_mret_w;
  logic        dec_ebreak_w;
  logic        dec_illegal_w;
  logic        dec_is_compressed_w;
  logic        dec_wb_en_w;

  logic [3:0]  rf_raddr1_w;
  logic [3:0]  rf_raddr2_w;
  logic [31:0] rf_rdata1_w;
  logic [31:0] rf_rdata2_w;
  logic        rf_we_w;
  logic [3:0]  rf_waddr_w;
  logic [31:0] rf_wdata_w;

  logic        issue_fire_w;

  logic        x_valid_q;
  logic [31:0] x_pc_q;
  logic [31:0] x_instr_q;
  logic [31:0] x_imm_q;
  logic [31:0] x_rs1_data_q;
  logic [31:0] x_rs2_data_q;
  logic [4:0]  x_rd_idx_q;
  logic [3:0]  x_alu_op_q;
  logic [2:0]  x_branch_op_q;
  logic        x_mul_en_q;
  logic        x_mem_req_q;
  logic        x_mem_we_q;
  logic [1:0]  x_mem_size_q;
  logic        x_mem_unsigned_q;
  logic        x_csr_en_q;
  logic [2:0]  x_csr_funct3_q;
  logic [11:0] x_csr_addr_q;
  logic        x_mret_q;
  logic        x_ebreak_q;
  logic        x_illegal_q;
  logic        x_is_compressed_q;
  logic        x_wb_en_q;

  logic [31:0] alu_result_unused_w;
  logic        alu_branch_taken_unused_w;
  logic [31:0] alu_branch_target_unused_w;

  logic        mul_start_w;
  logic        mul_busy_w;
  logic        mul_done_w;
  logic [31:0] mul_result_w;

  logic        lsu_mem_req_w;
  logic        lsu_mem_we_w;
  logic [3:0]  lsu_mem_be_w;
  logic [31:0] lsu_mem_addr_w;
  logic [31:0] lsu_mem_wdata_w;
  logic [31:0] lsu_load_data_w;
  logic        lsu_done_w;
  logic        lsu_stall_w;
  logic        lsu_misaligned_w;

  logic        ex_branch_taken_w;
  logic [31:0] ex_branch_target_w;
  logic        ex_wb_en_w;
  logic [4:0]  ex_wb_rd_idx_w;
  logic [31:0] ex_wb_data_w;
  logic [31:0] ex_mem_addr_unused_w;
  logic [31:0] ex_mem_wdata_unused_w;
  logic        ex_mem_req_unused_w;
  logic        ex_mem_we_unused_w;
  logic        ex_trap_req_w;
  logic [3:0]  ex_trap_cause_w;
  logic        ex_mret_req_w;
  logic        ex_stall_w;

  logic [31:0] csr_rdata_w;
  logic        csr_trap_redirect_valid_w;
  logic [31:0] csr_trap_redirect_pc_w;
  logic        csr_mret_redirect_valid_w;
  logic [31:0] csr_mret_redirect_pc_w;

  logic        boot_start_w;
  logic        boot_spi_req_w;
  logic [31:0] boot_spi_addr_w;
  logic        boot_iram_we_unused_w;
  logic [31:0] boot_iram_addr_unused_w;
  logic [31:0] boot_iram_wdata_unused_w;
  logic        boot_done_w;
  logic [31:0] boot_pc_w;
  logic        boot_fail_w;

  logic        boot_redirect_valid_w;
  logic        branch_redirect_valid_w;
  logic        trap_request_to_csr_w;
  logic [3:0]  trap_cause_to_csr_w;
  logic [31:0] trap_pc_to_csr_w;

  assign rf_raddr1_w = dec_rs1_idx_w[4] ? 4'd0 : dec_rs1_idx_w[3:0];
  assign rf_raddr2_w = dec_rs2_idx_w[4] ? 4'd0 : dec_rs2_idx_w[3:0];

  assign rf_we_w    = (top_state_q == TOP_STATE_RUN) && x_valid_q && ex_wb_en_w && !fail_stop_q && !ex_wb_rd_idx_w[4];
  assign rf_waddr_w = ex_wb_rd_idx_w[3:0];
  assign rf_wdata_w = ex_wb_data_w;

  assign issue_fire_w = (top_state_q == TOP_STATE_RUN) &&
                        !fail_stop_q &&
                        !x_valid_q &&
                        fetch_instr_valid_w &&
                        !boot_redirect_pending_q &&
                        !csr_trap_redirect_valid_w &&
                        !csr_mret_redirect_valid_w;

  assign mul_start_w = issue_fire_w && dec_mul_en_w && !dec_illegal_w;

  assign fetch_is_compressed_hint_w = instr_ready ? (instr_rdata[1:0] != 2'b11) : 1'b0;

  assign boot_start_w = (top_state_q == TOP_STATE_BOOT) && !boot_started_q;

  assign boot_redirect_valid_w   = (top_state_q == TOP_STATE_RUN) && boot_redirect_pending_q && !fetch_stall_w;
  assign branch_redirect_valid_w = x_valid_q && ex_branch_taken_w;

  assign trap_request_to_csr_w = (x_valid_q && ex_trap_req_w) ||
                                 (x_valid_q && x_ebreak_q) ||
                                 (x_valid_q && lsu_misaligned_w);

  assign trap_cause_to_csr_w = ex_trap_req_w                 ? ex_trap_cause_w :
                               (x_valid_q && x_ebreak_q)    ? 4'd3 :
                               (x_valid_q && lsu_misaligned_w && x_mem_we_q) ? 4'd6 :
                               (x_valid_q && lsu_misaligned_w) ? 4'd4 :
                               4'd0;

  assign trap_pc_to_csr_w = x_valid_q ? x_pc_q : fetch_pc_w;

  assign fetch_stall_w = (top_state_q != TOP_STATE_RUN) || fail_stop_q || x_valid_q;

  assign fetch_flush_w = issue_fire_w ||
                         boot_redirect_valid_w ||
                         csr_trap_redirect_valid_w ||
                         csr_mret_redirect_valid_w ||
                         branch_redirect_valid_w;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      top_state_q              <= TOP_STATE_INIT;
      fail_stop_q              <= 1'b0;
      boot_started_q           <= 1'b0;
      boot_redirect_pending_q  <= 1'b0;
      boot_redirect_pc_q       <= 32'd0;
      x_valid_q                <= 1'b0;
      x_pc_q                   <= 32'd0;
      x_instr_q                <= 32'd0;
      x_imm_q                  <= 32'd0;
      x_rs1_data_q             <= 32'd0;
      x_rs2_data_q             <= 32'd0;
      x_rd_idx_q               <= 5'd0;
      x_alu_op_q               <= 4'd0;
      x_branch_op_q            <= 3'd0;
      x_mul_en_q               <= 1'b0;
      x_mem_req_q              <= 1'b0;
      x_mem_we_q               <= 1'b0;
      x_mem_size_q             <= 2'd0;
      x_mem_unsigned_q         <= 1'b0;
      x_csr_en_q               <= 1'b0;
      x_csr_funct3_q           <= 3'd0;
      x_csr_addr_q             <= 12'd0;
      x_mret_q                 <= 1'b0;
      x_ebreak_q               <= 1'b0;
      x_illegal_q              <= 1'b0;
      x_is_compressed_q        <= 1'b0;
      x_wb_en_q                <= 1'b0;
    end else begin
      case (top_state_q)
        TOP_STATE_INIT: begin
          boot_started_q <= 1'b0;
          if (boot_mode_spi) begin
            top_state_q <= TOP_STATE_BOOT;
          end else begin
            top_state_q <= TOP_STATE_RUN;
          end
        end

        TOP_STATE_BOOT: begin
          if (boot_start_w) begin
            boot_started_q <= 1'b1;
          end
          if (boot_fail_w) begin
            top_state_q   <= TOP_STATE_FAIL;
            fail_stop_q   <= 1'b1;
            x_valid_q     <= 1'b0;
          end else if (boot_done_w) begin
            top_state_q             <= TOP_STATE_RUN;
            boot_started_q          <= 1'b0;
            boot_redirect_pending_q <= 1'b1;
            boot_redirect_pc_q      <= boot_pc_w;
            x_valid_q               <= 1'b0;
          end
        end

        TOP_STATE_RUN: begin
          if (boot_redirect_pending_q && !fetch_stall_w) begin
            boot_redirect_pending_q <= 1'b0;
          end

          if (issue_fire_w) begin
            x_valid_q         <= 1'b1;
            x_pc_q            <= fetch_pc_w;
            x_instr_q         <= fetch_instr_w;
            x_imm_q           <= dec_imm_w;
            x_rs1_data_q      <= rf_rdata1_w;
            x_rs2_data_q      <= rf_rdata2_w;
            x_rd_idx_q        <= dec_rd_idx_w;
            x_alu_op_q        <= dec_alu_op_w;
            x_branch_op_q     <= dec_branch_op_w;
            x_mul_en_q        <= dec_mul_en_w;
            x_mem_req_q       <= dec_mem_req_w;
            x_mem_we_q        <= dec_mem_we_w;
            x_mem_size_q      <= fetch_instr_w[13:12];
            x_mem_unsigned_q  <= (!dec_mem_we_w) && fetch_instr_w[14];
            x_csr_en_q        <= dec_csr_en_w;
            x_csr_funct3_q    <= fetch_instr_w[14:12];
            x_csr_addr_q      <= fetch_instr_w[31:20];
            x_mret_q          <= dec_mret_w;
            x_ebreak_q        <= dec_ebreak_w;
            x_illegal_q       <= dec_illegal_w;
            x_is_compressed_q <= dec_is_compressed_w;
            x_wb_en_q         <= dec_wb_en_w;
          end else if (x_valid_q && !ex_stall_w) begin
            x_valid_q         <= 1'b0;
            x_pc_q            <= x_pc_q;
            x_instr_q         <= x_instr_q;
            x_imm_q           <= x_imm_q;
            x_rs1_data_q      <= x_rs1_data_q;
            x_rs2_data_q      <= x_rs2_data_q;
            x_rd_idx_q        <= x_rd_idx_q;
            x_alu_op_q        <= x_alu_op_q;
            x_branch_op_q     <= x_branch_op_q;
            x_mul_en_q        <= x_mul_en_q;
            x_mem_req_q       <= x_mem_req_q;
            x_mem_we_q        <= x_mem_we_q;
            x_mem_size_q      <= x_mem_size_q;
            x_mem_unsigned_q  <= x_mem_unsigned_q;
            x_csr_en_q        <= x_csr_en_q;
            x_csr_funct3_q    <= x_csr_funct3_q;
            x_csr_addr_q      <= x_csr_addr_q;
            x_mret_q          <= x_mret_q;
            x_ebreak_q        <= x_ebreak_q;
            x_illegal_q       <= x_illegal_q;
            x_is_compressed_q <= x_is_compressed_q;
            x_wb_en_q         <= x_wb_en_q;
          end
        end

        TOP_STATE_FAIL: begin
          fail_stop_q <= 1'b1;
          x_valid_q   <= 1'b0;
        end

        default: begin
          top_state_q <= TOP_STATE_FAIL;
          fail_stop_q <= 1'b1;
          x_valid_q   <= 1'b0;
        end
      endcase
    end
  end

  fetch_unit u_fetch_unit (
    .reset_vector_i         (RV32EC_ZMMUL_RESET_VECTOR),
    .clk                    (clk),
    .rst_n                  (rst_n),
    .stall_i                (fetch_stall_w),
    .flush_i                (fetch_flush_w),
    .trap_redirect_valid_i  (csr_trap_redirect_valid_w),
    .trap_redirect_pc_i     (csr_trap_redirect_pc_w),
    .mret_redirect_valid_i  (csr_mret_redirect_valid_w),
    .mret_redirect_pc_i     (csr_mret_redirect_pc_w),
    .branch_redirect_valid_i(boot_redirect_valid_w | branch_redirect_valid_w),
    .branch_redirect_pc_i   (boot_redirect_valid_w ? boot_redirect_pc_q : ex_branch_target_w),
    .instr_ready_i          (instr_ready),
    .instr_rdata_i          (instr_rdata),
    .is_compressed_i        (fetch_is_compressed_hint_w),
    .instr_req_o            (fetch_instr_req_w),
    .instr_addr_o           (fetch_instr_addr_w),
    .pc_o                   (fetch_pc_w),
    .instr_valid_o          (fetch_instr_valid_w),
    .instr_o                (fetch_instr_w)
  );

  decode_control_unit u_decode_control_unit (
    .instr_i          (fetch_instr_w),
    .pc_i             (fetch_pc_w),
    .rs1_idx_o        (dec_rs1_idx_w),
    .rs2_idx_o        (dec_rs2_idx_w),
    .rd_idx_o         (dec_rd_idx_w),
    .imm_o            (dec_imm_w),
    .alu_op_o         (dec_alu_op_w),
    .branch_op_o      (dec_branch_op_w),
    .mul_en_o         (dec_mul_en_w),
    .mem_req_o        (dec_mem_req_w),
    .mem_we_o         (dec_mem_we_w),
    .csr_en_o         (dec_csr_en_w),
    .mret_o           (dec_mret_w),
    .ebreak_o         (dec_ebreak_w),
    .illegal_o        (dec_illegal_w),
    .is_compressed_o  (dec_is_compressed_w),
    .wb_en_o          (dec_wb_en_w)
  );

  regfile_16x32 u_regfile_16x32 (
    .clk      (clk),
    .rst_n    (rst_n),
    .raddr1_i (rf_raddr1_w),
    .raddr2_i (rf_raddr2_w),
    .we_i     (rf_we_w),
    .waddr_i  (rf_waddr_w),
    .wdata_i  (rf_wdata_w),
    .rdata1_o (rf_rdata1_w),
    .rdata2_o (rf_rdata2_w)
  );

  alu32_branch_unit u_alu32_branch_unit (
    .op_a_i          (x_rs1_data_q),
    .op_b_i          (x_rs2_data_q),
    .pc_i            (x_pc_q),
    .imm_i           (x_imm_q),
    .alu_op_i        (x_alu_op_q),
    .branch_op_i     (x_branch_op_q),
    .result_o        (alu_result_unused_w),
    .branch_taken_o  (alu_branch_taken_unused_w),
    .branch_target_o (alu_branch_target_unused_w)
  );

  multiplier_unit u_multiplier_unit (
    .clk      (clk),
    .rst_n    (rst_n),
    .start_i  (mul_start_w),
    .op_a_i   (rf_rdata1_w),
    .op_b_i   (rf_rdata2_w),
    .busy_o   (mul_busy_w),
    .done_o   (mul_done_w),
    .result_o (mul_result_w)
  );

  load_store_unit u_load_store_unit (
    .clk                   (clk),
    .rst_n                 (rst_n),
    .req_i                 (x_valid_q && x_mem_req_q),
    .we_i                  (x_mem_we_q),
    .size_i                (x_mem_size_q),
    .unsigned_i            (x_mem_unsigned_q),
    .base_addr_i           (x_rs1_data_q),
    .offset_i              (x_imm_q),
    .store_data_i          (x_rs2_data_q),
    .mem_ready_i           (data_ready),
    .mem_rdata_i           (data_rdata),
    .trap_on_misaligned_i  (1'b1),
    .mem_req_o             (lsu_mem_req_w),
    .mem_we_o              (lsu_mem_we_w),
    .mem_be_o              (lsu_mem_be_w),
    .mem_addr_o            (lsu_mem_addr_w),
    .mem_wdata_o           (lsu_mem_wdata_w),
    .load_data_o           (lsu_load_data_w),
    .done_o                (lsu_done_w),
    .stall_o               (lsu_stall_w),
    .misaligned_o          (lsu_misaligned_w)
  );

  execute_writeback_unit u_execute_writeback_unit (
    .clk          (clk),
    .rst_n        (rst_n),
    .pc_i         (x_pc_q),
    .rs1_data_i   (x_rs1_data_q),
    .rs2_data_i   (x_rs2_data_q),
    .imm_i        (x_imm_q),
    .rd_idx_i     (x_rd_idx_q),
    .alu_op_i     (x_alu_op_q),
    .branch_op_i  (x_branch_op_q),
    .mul_en_i     (x_valid_q && x_mul_en_q),
    .mem_req_i    (x_valid_q && x_mem_req_q),
    .mem_we_i     (x_mem_we_q),
    .csr_en_i     (x_valid_q && x_csr_en_q),
    .mret_i       (x_valid_q && x_mret_q),
    .illegal_i    (x_valid_q && x_illegal_q),
    .load_data_i  (lsu_load_data_w),
    .load_ready_i (lsu_done_w),
    .mul_result_i (mul_result_w),
    .mul_done_i   (mul_done_w),
    .csr_rdata_i  (csr_rdata_w),
    .branch_taken_o(ex_branch_taken_w),
    .branch_target_o(ex_branch_target_w),
    .wb_en_o      (ex_wb_en_w),
    .wb_rd_idx_o  (ex_wb_rd_idx_w),
    .wb_data_o    (ex_wb_data_w),
    .mem_addr_o   (ex_mem_addr_unused_w),
    .mem_wdata_o  (ex_mem_wdata_unused_w),
    .mem_req_o    (ex_mem_req_unused_w),
    .mem_we_o     (ex_mem_we_unused_w),
    .trap_req_o   (ex_trap_req_w),
    .trap_cause_o (ex_trap_cause_w),
    .mret_req_o   (ex_mret_req_w),
    .stall_o      (ex_stall_w)
  );

  csr_trap_controller u_csr_trap_controller (
    .clk                    (clk),
    .rst_n                  (rst_n),
    .csr_en_i               (x_valid_q && x_csr_en_q),
    .csr_we_i               (x_valid_q && x_csr_en_q && (x_csr_funct3_q != 3'b010)),
    .csr_addr_i             (x_csr_addr_q),
    .csr_wdata_i            (x_rs1_data_q),
    .trap_req_i             (trap_request_to_csr_w),
    .trap_cause_i           (trap_cause_to_csr_w),
    .trap_pc_i              (trap_pc_to_csr_w),
    .ext_irq_i              ((top_state_q == TOP_STATE_RUN) && !fail_stop_q && ext_irq),
    .mret_i                 (x_valid_q && ex_mret_req_w),
    .csr_rdata_o            (csr_rdata_w),
    .trap_redirect_valid_o  (csr_trap_redirect_valid_w),
    .trap_redirect_pc_o     (csr_trap_redirect_pc_w),
    .mret_redirect_valid_o  (csr_mret_redirect_valid_w),
    .mret_redirect_pc_o     (csr_mret_redirect_pc_w)
  );

  boot_rom_loader u_boot_rom_loader (
    .clk                 (clk),
    .rst_n               (rst_n),
    .start_i             (boot_start_w),
    .spi_ready_i         (spi_ready),
    .spi_rdata_i         (spi_rdata),
    .iram_ready_i        (1'b1),
    .validation_enable_i (1'b0),
    .spi_req_o           (boot_spi_req_w),
    .spi_addr_o          (boot_spi_addr_w),
    .iram_we_o           (boot_iram_we_unused_w),
    .iram_addr_o         (boot_iram_addr_unused_w),
    .iram_wdata_o        (boot_iram_wdata_unused_w),
    .done_o              (boot_done_w),
    .boot_pc_o           (boot_pc_w),
    .fail_stop_o         (boot_fail_w)
  );

  always_comb begin
    instr_req   = 1'b0;
    instr_addr  = 32'd0;
    data_req    = 1'b0;
    data_we     = 1'b0;
    data_be     = 4'd0;
    data_addr   = 32'd0;
    data_wdata  = 32'd0;
    spi_req     = 1'b0;
    spi_addr    = 32'd0;
    fail_stop   = fail_stop_q;

    if (top_state_q == TOP_STATE_FAIL) begin
      fail_stop = 1'b1;
    end else if (!fail_stop_q) begin
      if (top_state_q == TOP_STATE_BOOT) begin
        spi_req    = boot_spi_req_w;
        spi_addr   = boot_spi_addr_w;
      end else if (top_state_q == TOP_STATE_RUN) begin
        instr_req  = fetch_instr_req_w;
        instr_addr = fetch_instr_addr_w;
        data_req   = lsu_mem_req_w;
        data_we    = lsu_mem_we_w;
        data_be    = lsu_mem_be_w;
        data_addr  = lsu_mem_addr_w;
        data_wdata = lsu_mem_wdata_w;
      end
    end
  end

endmodule
